class ProductOrderDao:
    def init(self):
        self._product_orders = []

    def add_product_order(self, product_order):
        self._product_orders.append(product_order)

    def get_product_orders(self):
        return self._product_orders

    def get_product_order_by_id(self, order_id):
        for product_order in self._product_orders:
            if product_order.order_id == order_id:
                return product_order
        return None

    def update_product_order(self, order_id, updated_product_order):
        product_order = self.get_product_order_by_id(order_id)
        if product_order:
            product_order.product_name = updated_product_order.product_name
            product_order.quantity = updated_product_order.quantity
            product_order.order_date = updated_product_order.order_date
            product_order.delivery_date = updated_product_order.delivery_date

    def delete_product_order(self, order_id):
        product_order = self.get_product_order_by_id(order_id)
        if product_order:
            self._product_orders.remove(product_order)
